import { Suspense } from 'react';
import { BookOpen, Music, History, Sparkles } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import Link from 'next/link';
import { getPeriodosHistoria, getInstrumentosTradicionais, getHistoriaStats } from '@/src/lib/supabase/queries/historia';

export const metadata = {
  title: 'História da Música | Nipo School',
  description: 'Explore a rica história da música japonesa',
};

// Ícones para os períodos históricos
const periodIcons = ['🏯', '🎭', '🎌', '🌸', '🎸', '🎵', '🎼'];

async function HistoriaContent() {
  // Busca dados reais do banco
  const [periodos, instrumentos, stats] = await Promise.all([
    getPeriodosHistoria(),
    getInstrumentosTradicionais(),
    getHistoriaStats()
  ]);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
          <History className="w-8 h-8 text-amber-600" />
          História da Música Japonesa
        </h1>
        <p className="text-gray-600 mt-2">
          Explore a rica história e evolução da música japonesa através dos séculos
        </p>
      </div>

      {/* Estatísticas */}
      {stats.totalPeriodos > 0 && (
        <div className="grid grid-cols-3 gap-4">
          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Períodos</CardDescription>
              <CardTitle className="text-3xl">{stats.totalPeriodos}</CardTitle>
            </CardHeader>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Compositores</CardDescription>
              <CardTitle className="text-3xl">{stats.totalCompositores}</CardTitle>
            </CardHeader>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Obras</CardDescription>
              <CardTitle className="text-3xl">{stats.totalObras}</CardTitle>
            </CardHeader>
          </Card>
        </div>
      )}

      {/* Introdução */}
      <Card className="bg-gradient-to-r from-amber-50 to-orange-50 border-amber-200">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-amber-900">
            <Sparkles className="w-5 h-5" />
            Jornada Musical Milenar
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-amber-800 leading-relaxed">
            A música japonesa possui uma história rica que se estende por mais de mil anos, 
            desde as antigas melodias da corte imperial até o moderno J-Pop que conquista o 
            mundo. Cada período histórico contribuiu com elementos únicos que formam o 
            fascinante mosaico sonoro da cultura japonesa.
          </p>
        </CardContent>
      </Card>

      {/* Períodos Históricos */}
      <div>
        <h2 className="text-2xl font-bold text-gray-900 mb-4 flex items-center gap-2">
          <BookOpen className="w-6 h-6 text-blue-600" />
          Períodos Históricos
        </h2>
        {periodos.length > 0 ? (
          <div className="grid gap-4">
            {periodos.map((periodo, index) => {
              const descricao = periodo.descricao_curta || periodo.descricao_completa || 'Período histórico importante da música japonesa';
              const topicosCount = periodo.caracteristicas_principais?.topicos?.length || 0;
              
              return (
                <Card key={periodo.id} className="hover:shadow-lg transition-shadow">
                  <CardHeader>
                    <div className="flex items-start justify-between">
                      <div className="flex items-center gap-3">
                        <span className="text-4xl">{periodIcons[index % periodIcons.length]}</span>
                        <div>
                          <CardTitle className="text-xl">
                            {periodo.nome}
                            {periodo.periodo_inicio && periodo.periodo_fim && (
                              <span className="text-sm font-normal text-gray-600 ml-2">
                                ({periodo.periodo_inicio}-{periodo.periodo_fim})
                              </span>
                            )}
                          </CardTitle>
                          <CardDescription className="mt-1">
                            {typeof descricao === 'string' ? descricao : descricao?.texto || 'Explore este período'}
                          </CardDescription>
                        </div>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center justify-between">
                      <span className="text-sm text-gray-600">
                        {topicosCount > 0 ? `${topicosCount} tópicos de estudo` : 'Conteúdo disponível'}
                      </span>
                      <Link 
                        href={`/alunos/historia/${periodo.id}`}
                        className="text-blue-600 hover:text-blue-800 font-medium text-sm transition-colors"
                      >
                        Explorar →
                      </Link>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        ) : (
          <Card>
            <CardContent className="pt-6">
              <p className="text-gray-600 text-center">
                Nenhum período histórico cadastrado ainda.
              </p>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Instrumentos Tradicionais */}
      <div>
        <h2 className="text-2xl font-bold text-gray-900 mb-4 flex items-center gap-2">
          <Music className="w-6 h-6 text-purple-600" />
          Instrumentos Tradicionais
        </h2>
        {instrumentos.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {instrumentos.slice(0, 4).map((instrumento, index) => {
              const descricao = typeof instrumento.descricao === 'string' 
                ? instrumento.descricao 
                : instrumento.descricao?.texto || instrumento.descricao?.descricao || 'Instrumento tradicional japonês';
              
              return (
                <Card key={index} className="bg-gradient-to-br from-purple-50 to-pink-50 border-purple-200">
                  <CardHeader>
                    <div className="flex items-center gap-3">
                      <span className="text-3xl">🎵</span>
                      <div>
                        <CardTitle className="text-lg text-purple-900">{instrumento.nome}</CardTitle>
                        {instrumento.periodo_origem && (
                          <Badge variant="outline" className="mt-1">
                            Período {instrumento.periodo_origem}
                          </Badge>
                        )}
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <p className="text-purple-800 text-sm">{descricao}</p>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        ) : (
          <Card className="bg-gradient-to-br from-purple-50 to-pink-50 border-purple-200">
            <CardContent className="pt-6">
              <p className="text-purple-800 text-center">
                Instrumentos tradicionais serão adicionados em breve.
              </p>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Curiosidades */}
      <Card className="bg-gradient-to-r from-indigo-50 to-blue-50 border-indigo-200">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-indigo-900">
            <Sparkles className="w-5 h-5" />
            Você Sabia?
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3 text-indigo-800">
          <p>
            🎵 O <strong>gagaku</strong> é uma das formas de música orquestral mais antigas do mundo ainda praticadas.
          </p>
          <p>
            🎭 A música do teatro <strong>Noh</strong> influenciou compositores ocidentais como Benjamin Britten.
          </p>
          <p>
            🎌 O <strong>enka</strong>, estilo musical melancólico, ainda é extremamente popular entre gerações mais velhas.
          </p>
          <p>
            🎸 O J-Pop japonês influenciou significativamente a música pop na Coreia (K-Pop) e em toda a Ásia.
          </p>
        </CardContent>
      </Card>
    </div>
  );
}

export default function HistoriaPage() {
  return (
    <Suspense fallback={<div className="p-8">Carregando conteúdo...</div>}>
      <HistoriaContent />
    </Suspense>
  );
}
